if(!source == null || !source == ""){
var sourcePolicyId = source._refResourceId;
logger.error("sourcePolicyId ref: "+sourcePolicyId);

try {

    var policyResponse = openidm.query(
        "managed/alpha_kyid_enrollment_access_policy",{
             "_queryFilter": '_id eq "' + sourcePolicyId + '"'
        },
        ["name"]
    );
    logger.error("policy Response: " + JSON.stringify(policyResponse));

    if (policyResponse.result && policyResponse.result.length == 1) {

		var policyName = policyResponse.result[0].name;
		logger.error("policy in response : "+policyName);

    } else {
		logger.error("Exception occurred during role to policy link " );
    }
} catch (e) {
    logger.error("Exception occurred: " + e);  
}
